```json
{
  "global": "Navigate the web-based event ticketing interface to locate and select a ticket for a combat-sports event (e.g., boxing, kickboxing, MMA) that is categorically similar to professional boxing.",
  "subtasks": [
    {
      "subtask": "Open the event listing or ticketing module",
      "atomics": [
        "Identify and click the navigation link or menu item that leads to Events or Ticketing",
        "Wait for the event catalog page to fully load"
      ]
    },
    {
      "subtask": "Search or filter events to surface combat-sports categories",
      "atomics": [
        "Locate the search bar or category/filter controls on the event listing page",
        "Enter a query or select a filter that targets combat sports (e.g., 'boxing', 'fighting', 'martial arts', 'combat')",
        "Submit the search or apply the filter and wait for results to update"
      ]
    },
    {
      "subtask": "Identify the event most similar to professional boxing",
      "atomics": [
        "Scan returned event titles and descriptions for keywords indicating combat sports (boxing, kickboxing, MMA, wrestling, fight night)",
        "Select the event whose description most closely matches professional boxing (ring sport, weight classes, bouts, judges)"
      ]
    },
    {
      "subtask": "Select a ticket for the identified event",
      "atomics": [
        "Click on the target event to open its detail or ticket-selection page",
        "Choose a ticket type or quantity if a selection step is required",
        "Click the 'Select', 'Add to Cart', or equivalent confirmation button to register the ticket selection"
      ]
    }
  ],
  "global_atomics": [
    "Verify that the final UI state reflects the selected ticket (confirmation message, cart item, or highlighted selection) for the combat-sports event"
  ],
  "gold_actions": {
    "global": "Use the WorkArena++ / ServiceNow event ticketing UI to filter events by combat-sports category and click the ticket-selection control for the boxing-like event.",
    "subtasks": [
      {
        "subtask": "Open the event listing or ticketing module",
        "atomics": [
          "Click 'Events' or 'Ticketing' in the top navigation bar or application menu",
          "Assert that a list of events is rendered on screen before proceeding"
        ]
      },
      {
        "subtask": "Search or filter events to surface combat-sports categories",
        "atomics": [
          "Click the search input field labeled 'Search events' or activate the category filter dropdown",
          "Type 'boxing' (or 'combat' / 'fighting') into the search field or select the Sports > Combat Sports category option",
          "Press Enter or click the 'Search' / 'Apply' button and wait for the filtered event list to render"
        ]
      },
      {
        "subtask": "Identify the event most similar to professional boxing",
        "atomics": [
          "Read event titles in the results list and flag items containing terms like 'boxing', 'fight night', 'bout', 'ring', 'MMA', 'kickboxing'",
          "Click the event whose title/description best matches professional boxing (prioritize 'boxing' exact match, then ring-sport indicators)"
        ]
      },
      {
        "subtask": "Select a ticket for the identified event",
        "atomics": [
          "Click the event row or card to navigate to its ticket detail page",
          "If a ticket-type dropdown or radio group is shown, choose the default or lowest-tier ticket option",
          "Click the 'Select Ticket', 'Reserve', or 'Add to Cart' button to complete the selection action"
        ]
      }
    ],
    "global_atomics": [
      "Confirm the page displays a success indicator (e.g., 'Ticket selected', cart count increments, or a confirmation banner) referencing the combat-sports event"
    ]
  }
}
```
